{
  "start_url": "https://dashdoor-prod.rlgym.turing.com",
  "task_statement": "Order mac & cheese from West diner, select the extra cheese add on",
  "task_id": "item-addon-order-001",
  "task_type": "GUI Comprehension, Action Execution",
  "simulator_config": {
    "bootstrap_data": {
      "date": "2025-12-19T12:00:00-08:00",
      "timezone": "America/Los_Angeles",
      "user": "lena.bennett71@example.com"
    }
  },
  "grader_config": {
    "state_grader_configs": [
      {
        "assertions": [
          {
            "operator": "STRING_EQUALS",
            "path_to_actual": "$.restaurantId",
            "paths_to_expected": [
              "$[1].restaurants[0].id"
            ]
          },
          {
            "operator": "STRING_EQUALS",
            "path_to_actual": "$.items[0].name",
            "paths_to_expected": [
              "$[2].items[0].name"
            ]
          },
          {
            "expected": [
              "==1"
            ],
            "operator": "ARRAY_LENGTH_MATCH",
            "path_to_actual": "$.items[*]"
          },
          {
            "operator": "NUMERIC_MATCH",
            "path_to_actual": "$.items[0].quantity",
            "expected": [
              "==1"
            ]
          },
          {
            "operator": "STRING_EQUALS",
            "path_to_actual": "$.items[0].modifications[0].options[0].optionId",
            "paths_to_expected": [
              "$[3].modification.options[0].id"
            ]
          }
        ],
        "path_to_actual": "$.orders[0]"
      }
    ],
    "extract_states_config": {
      "expected_state_functions": [
        {
          "args": {
            "user": "lena.bennett71@example.com"
          },
          "function": "get_user_address"
        },
        {
          "args": {
            "lat": "$[0].address.lat",
            "lng": "$[0].address.lng",
            "limit": 1,
            "name": "West diner"
          },
          "function": "get_restaurants"
        },
        {
          "args": {
            "limit": 1,
            "keywords": [
              "mac & cheese"
            ],
            "restaurant_id": "$[1].restaurants[0].id"
          },
          "function": "get_items"
        },
        {
          "args": {
            "item_id": "$[2].items[0].id",
            "modification_name": "add-ons",
            "option_name": "extra cheese"
          },
          "function": "get_modifications"
        }
      ]
    }
  }
}

