{
  "start_url": "https://dashdoor-prod.rlgym.turing.com",
  "task_statement": "I want to get either a grain bowl or a cucumber salad from the nearest Ethiopian restaurant that has both items on the menu, choosing the most expensive option, and if they cost the same, pick the one with the higher rating. Have it delivered to my apartment address.",
  "task_id": "nearest-cheapest-choice-001",
  "task_type": "Multi-Step Task Planning, Action Execution, GUI Comprehension, Element Identification",
  "simulator_config": {
    "bootstrap_data": {
      "date": "2025-12-19T12:00:00-08:00",
      "timezone": "America/Los_Angeles",
      "user": "quinn.bennett2227@inbox.local"
    }
  },
  "grader_config": {
    "state_grader_configs": [
      {
        "assertions": [
          {
            "operator": "STRING_EQUALS",
            "paths_to_expected": [
              "$[0].address.id"
            ]
          }
        ],
        "path_to_actual": "$.orders[0].deliveryAddress.id"
      },
      {
        "assertions": [
          {
            "operator": "STRING_EQUALS",
            "path_to_actual": "$.items[0].id",
            "paths_to_expected": [
              "$[2].items[0].id"
            ]
          },
          {
            "expected": [
              "==1"
            ],
            "operator": "ARRAY_LENGTH_MATCH",
            "path_to_actual": "$.items[*]"
          }
        ],
        "path_to_actual": "$.orders[0]"
      }
    ],
    "extract_states_config": {
      "expected_state_functions": [
        {
          "args": {
            "type": "apartment",
            "user": "quinn.bennett2227@inbox.local"
          },
          "function": "get_user_address"
        },
        {
          "args": {
            "lat": "$[0].address.lat",
            "lng": "$[0].address.lng",
            "limit": 1,
            "filters": {
              "cuisines": [
                "Ethiopian"
              ]
            },
            "sort_type": [
              {
                "key": "distance",
                "order": "asc"
              }
            ]
          },
          "function": "get_restaurants"
        },
        {
          "args": {
            "limit": 1,
            "keywords": [
              "cucumber salad",
              "grain bowl"
            ],
            "sort_type": [
              {
                "key": "price",
                "order": "desc"
              },
              {
                "key": "rating",
                "order": "desc"
              }
            ],
            "restaurant_id": "$[1].restaurants[0].id"
          },
          "function": "get_items"
        }
      ]
    }
  }
}

